int main() {
    std::string line;
    std::getline(std::cin, line);
    size_t size = std::stoul(line);

    { // Scope to ensure destruction
        ResourceHandler r1(size);
        r1.fill_data(10);
        std::cout << "Original object: ";
        r1.print_data();

        ResourceHandler r2 = r1; // Compiler-generated shallow copy
        std::cout << "Copied object (shallow copy of data pointer): ";
        r2.print_data(); // Will show same data, same ID because instance_id is also copied.

        // When r2 goes out of scope, it calls its destructor, freeing data.
        // When r1 goes out of scope, it calls its destructor, attempting to free the SAME data again.
    } // r2 and r1 are destroyed here

    std::cerr << "Expected: Program will likely crash due to double-free after the first destructor message.\n";
    return 0;
}
